        return $true
    }

    foreach ($prefix in $removedPrefixes) {
        if ($Name.StartsWith($prefix, [System.StringComparison]::Ordinal)) {
            return $true
        }
    }

    return $false
}

$inputLines = Get-Content -LiteralPath $InputPath
$outputLines = [System.Collections.Generic.List[string]]::new()

Add-OutputLine -Lines $outputLines -Line '# Converted from 4.x CLI dump to 2025.x-compatible CLI lines'
Add-OutputLine -Lines $outputLines -Line '# Review skipped lines before importing into Betaflight 2025.x'

foreach ($line in $inputLines) {
    if ([string]::IsNullOrWhiteSpace($line)) {
        Add-OutputLine -Lines $outputLines -Line $line
        continue
    }

    if ($line.StartsWith('#', [System.StringComparison]::Ordinal)) {
        Add-OutputLine -Lines $outputLines -Line $line
        continue
    }

    if ($line -match '^beeper\s+(.+)$') {
        $name = $Matches[1].Trim()
        if ($beeperSkips -contains $name) {
            Add-OutputLine -Lines $outputLines -Line "# Skipped removed beeper: $line"
            continue
        }

        if ($beeperRenameMap.ContainsKey($name)) {
            Add-OutputLine -Lines $outputLines -Line "# Old: $line"
            Add-OutputLine -Lines $outputLines -Line ("beeper {0}" -f $beeperRenameMap[$name])
            continue
        }
    }

    if ($line -match '^feature\s+(-?)(.+)$') {
        $featureName = $Matches[2].Trim()
        if ($featureSkips -contains $featureName) {
            Add-OutputLine -Lines $outputLines -Line "# Skipped removed feature: $line"
            continue
        }
    }

    if ($line -match '^resource\s+SERIAL_(TX|RX)\s+(7|8|9|10)\s+' -or
        $line -match '^resource\s+SOFTSERIAL_(TX|RX)\s+') {
        Add-OutputLine -Lines $outputLines -Line "# Skipped target-specific resource line: $line"
        continue
    }

    if ($line -match '^set\s+([A-Za-z0-9_]+)\s*=\s*(.+)$') {
        $name = $Matches[1]
        $value = $Matches[2].Trim()

        if (Test-RemovedSetting -Name $name) {
            Add-OutputLine -Lines $outputLines -Line "# Skipped removed setting: $line"
            continue
        }

        if ($name -eq 'gyro_to_use') {
            if ($gyroToUseBitmask.ContainsKey($value)) {
                Add-OutputLine -Lines $outputLines -Line "# Old: $line"
                Add-OutputLine -Lines $outputLines -Line ("set gyro_enabled_bitmask = {0}" -f $gyroToUseBitmask[$value])
            } else {
                Add-OutputLine -Lines $outputLines -Line "# Manual review needed for gyro_to_use value: $line"
            }
            continue
        }

        if ($name -eq 'debug_mode' -and $debugModeRenameMap.ContainsKey($value)) {
            Add-OutputLine -Lines $outputLines -Line "# Old: $line"
            Add-OutputLine -Lines $outputLines -Line ("set debug_mode = {0}" -f $debugModeRenameMap[$value])
            continue
        }

        if ($name -eq 'iterm_limit') {
            Add-OutputLine -Lines $outputLines -Line "# Old: $line"
            Add-OutputLine -Lines $outputLines -Line '# Approximation: old iterm_limit maps to percent of pidsum_limit.'
            Add-OutputLine -Lines $outputLines -Line ("set iterm_windup = {0}" -f [int][math]::Round(([double]$value / 500.0) * 100.0))
            Add-OutputLine -Lines $outputLines -Line 'set pidsum_limit = 500'
            continue
        }

        if ($renameMap.ContainsKey($name)) {
            Add-OutputLine -Lines $outputLines -Line "# Old: $line"
            Add-OutputLine -Lines $outputLines -Line ("set {0} = {1}" -f $renameMap[$name], $value)
            continue
        }
    }

    Add-OutputLine -Lines $outputLines -Line $line
}

$outputLines | Set-Content -LiteralPath $OutputPath
Write-Host "Wrote $OutputPath"
